const text = $input.first().json.data; // Предположим, текст лежит в поле data

let cleanText = text
  // 1. Убираем всё содержимое в фигурных {}, круглых () и квадратных [] скобках
  .replace(/\{[^}]*\}/g, ' ')
  .replace(/\([^)]*\)/g, ' ')
  .replace(/\[[^\]]*\]/g, ' ')

  // 2. Убираем всё, что не является буквой (любого языка), цифрой или пробелом
  // Это удалит: #, -, ., ,, !, ?, :, ;, /, \, |, @, $, %, ^, &, *, +, =, ~, `, " , '
  .replace(/[^\p{L}\p{N}\s]/gu, ' ')

  // 3. Убираем специфический мусор, который мог остаться словами
  .replace(/Cookie Policy|Privacy Policy|All Rights Reserved|Menu|Search|Sign In/gi, '')

  // 4. Схлопываем множественные пробелы и переносы в один пробел
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 5000);

return [{ json: { clean_site_text: cleanText } }];

// Достаём сырые данные из нод
const experienceRaw = $('CV GENERATION EXPRERIENCE').first().json.content.parts[0].text //← текст из ноды Experience
const skillsRaw = $('CV GENERATION SKILLS').first().json.content.parts[0].text    // ← текст из ноды Skills  
const summaryRaw = $input.first().json.content.parts[0].text   // ← текст из ноды Summary
const baseCv = $('base-cv').first().json.content       // ← текст из ноды Base CV (для имени, контактов, education, languages)

// ── Парсим Experience ──
// Формат: "Company | Dates\n* bullet\n* bullet"
function parseExperience(raw) {
  // Убираем экранирование если строка пришла как JSON-строка
  let text = raw.trim();
  if (text.startsWith('"')) {
    try { text = JSON.parse(text); } catch(e) {}
  }

  // Парсим JSON массив
  let jobs;
  try {
    jobs = JSON.parse(text);
  } catch(e) {
    // Fallback — старый plain text парсер
    return text.trim().split(/\n\n+/).map(job => {
      const lines = job.trim().split('\n');
      const header = lines[0].trim();
      const bullets = lines
        .slice(1)
        .filter(l => l.trim().startsWith('*') || l.trim().startsWith('-'))
        .map(l => `* ${l.replace(/^[\*\-]\s*/, '').trim()}`);
      return `**${header}**\n${bullets.join('\n')}`;
    }).join('\n\n');
  }

  return jobs.map(job => {
    const header = `${job.company} | ${job.dates}`;
    const bullets = job.experience.map(b => `* ${b}`);
    return `**${header}**\n${bullets.join('\n')}`;
  }).join('\n\n');
}


// ── Парсим Skills ──
// Формат: "Category: skill1, skill2"
function parseSkills(raw) {
  let text = cleanRaw(raw);

  // Пробуем парсить как JSON массив
  try {
    const arr = JSON.parse(text);
    if (Array.isArray(arr)) {
      return arr.map(l => {
        const [category, ...rest] = l.split(':');
        return `**${category.trim()}:** ${rest.join(':').trim()}`;
      }).join('\n');
    }
  } catch(e) {}

  // Fallback — plain text
  return text.split('\n')
    .filter(l => l.includes(':'))
    .map(l => {
      const [category, ...rest] = l.split(':');
      return `**${category.trim()}:** ${rest.join(':').trim()}`;
    })
    .join('\n');
}

// ── Достаём Education и Languages из Base CV ──
function extractSection(text, sectionName) {
  const regex = new RegExp(`###\\s*${sectionName}\\s*\\n([\\s\\S]*?)(?=###|$)`, 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

function extractHeader(text) {
  // Берём первые две строки — имя и контакты
  const lines = text.trim().split('\n');
  const nameLine = lines.find(l => l.startsWith('#')) || lines[0];
  const contactLine = lines.find(l => l.includes('@') || l.includes('+')) || '';
  return { name: nameLine.replace(/^#+\s*/, '').trim(), contacts: contactLine.trim() };
}

function cleanRaw(raw) {
  return raw
    .trim()
    .replace(/^"+|"+$/g, '')       // кавычки в начале и конце
    .replace(/\\n/g, '\n')         // экранированные переносы
    .replace(/\\"/g, '"')          // экранированные кавычки
    .replace(/\\u2013/g, '–')      // экранированные тире
    .trim();
}

function cleanSummary(raw) {
  let text = cleanRaw(raw);

  // Пробуем парсить как JSON
  try {
    const parsed = JSON.parse(text);
    // Объект с полем summary
    if (parsed?.summary) return parsed.summary.trim();
    if (parsed?.Summary) return parsed.Summary.trim();
    // Массив — берём первый элемент
    if (Array.isArray(parsed)) return parsed[0]?.summary || parsed[0]?.text || parsed[0] || text;
  } catch(e) {}

  return text.trim();
}

const experience = parseExperience(experienceRaw);
const skills = parseSkills(cleanRaw(skillsRaw));
const summary = cleanSummary(summaryRaw).trim();
const education = extractSection(baseCv, 'Education');
const languages = extractSection(baseCv, 'Languages');
const { name, contacts } = extractHeader(baseCv);

// ── Собираем финальный Markdown ──
const markdown = `# ${name}
**${contacts}**

---

### Summary
${summary}

### Skills
${skills}

### Experience
${experience}

### Education
${education}

### Languages
${languages}`;

// ── Конвертируем Markdown в HTML ──
function markdownToHtml(md) {
  const lines = md.split(/\r?\n/);
  const html = [];
  let inList = false;

  for (let line of lines) {
    line = line.trim();

    if (!line) {
      if (inList) { html.push('</ul>'); inList = false; }
      continue;
    }

    line = line
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/\[(.*?)\]\((.*?)\)/g, '<a target="_blank" href="$2">$1</a>');

    if (line.startsWith('### ')) {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push(`<h3>${line.substring(4)}</h3>`);
    } else if (line.startsWith('## ')) {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push(`<h2>${line.substring(3)}</h2>`);
    } else if (line.startsWith('# ')) {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push(`<h1>${line.substring(2)}</h1>`);
    } else if (line === '---') {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push('<hr>');
    } else if (line.startsWith('* ') || line.startsWith('- ')) {
      if (!inList) { html.push('<ul>'); inList = true; }
      html.push(`<li>${line.substring(2)}</li>`);
    } else {
      if (inList) { html.push('</ul>'); inList = false; }
      if (html.length > 0 && html[html.length - 1].startsWith('<h1>')) {
        html.push(`<p class="contact-info">${line}</p>`);
      } else {
        html.push(`<p>${line}</p>`);
      }
    }
  }

  if (inList) html.push('</ul>');
  return html.join('\n');
}

const htmlString = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, Helvetica, sans-serif; line-height: 1.4; color: #222; margin: 40px; font-size: 13px; }
    h1 { text-align: center; margin: 0 0 5px 0; color: #000; font-size: 24px; letter-spacing: 0.5px; }
    .contact-info { text-align: center; font-size: 12px; color: #444; margin: 0 0 15px 0; }
    hr { border: none; border-top: 1px solid #ddd; margin: 15px 0; }
    h3 { border-bottom: 1px solid #333; padding-bottom: 2px; margin-top: 15px; margin-bottom: 8px; font-size: 14px; text-transform: uppercase; color: #111; }
    p { margin: 4px 0; }
    ul { margin: 4px 0 10px 0; padding-left: 20px; }
    li { margin-bottom: 4px; }
    a { color: #0056b3; text-decoration: none; }
    strong { color: #000; font-weight: 600; }
  </style>
</head>
<body>
${markdownToHtml(markdown)}
</body>
</html>`;

const binaryData = Buffer.from(htmlString, 'utf-8');

return [{
  json: { filename: 'resume.html' },
  binary: {
    data: await this.helpers.prepareBinaryData(binaryData, 'index.html', 'text/html')
  }
}];
